module pulse_detect #(
    parameter s0 = 2'b00,
    parameter s1 = 2'b01,
    parameter s2 = 2'b10,
    parameter s3 = 2'b11
) (
    input clk,
    input rst_n,
    input data_in,
    output reg data_out
);

    localparam IDLE = 2'b00;
    localparam WAIT_FOR_FIRST_ONE = 2'b01;
    localparam WAIT_FOR_SECOND_ZERO = 2'b10;
    localparam PULSE_END = 2'b11;

    reg [1:0] state, next_state;

    always @(*) begin
        case (state)
            IDLE: begin
                if (data_in == 1'b1) begin
                    next_state = WAIT_FOR_FIRST_ONE;
                end else begin
                    next_state = IDLE;
                end
            end

            WAIT_FOR_FIRST_ONE: begin
                if (data_in == 1'b0) begin
                    next_state = WAIT_FOR_SECOND_ZERO;
                end else begin
                    next_state = WAIT_FOR_FIRST_ONE;
                end
            end

            WAIT_FOR_SECOND_ZERO: begin
                if (data_in == 1'b1) begin
                    next_state = PULSE_END;
                end else begin
                    next_state = WAIT_FOR_SECOND_ZERO;
                end
            end

            PULSE_END: begin
                if (data_in == 1'b0) begin
                    next_state = IDLE;
                end else begin
                    next_state = WAIT_FOR_FIRST_ONE;
                end
            end

            default: next_state = IDLE;
        endcase
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= IDLE;
        end else begin
            state <= next_state;
        end
    end

    always @(*) begin
        if ((state == PULSE_END) && (data_in == 1'b0)) begin
            data_out = 1'b1;
        end else begin
            data_out = 1'b0;
        end
    end
endmodule
